scripts.sourcepoint:
(function() {
  var _cd = { consentStatus: { rejectedAll: true, consentedAll: false }, applies: true };
  var _iotech = window.location.host.indexOf('io-tech.fi') >= 0;
  var _sp = window._sp_ = window._sp_ || {};
  _sp.config = _sp.config || {};
  _sp.executeMessaging = function() {};
  _sp.loadPrivacyManagerModal = function() {};
  _sp.addEventListener = function(evt, cb) {
    if (evt === 'onConsentReady') { try { cb(_cd); } catch(e) {} }
    else if (evt === 'onSPPMObjectReady') { try { cb({}); } catch(e) {} }
  };
  _sp.removeEventListener = function() {};
  _sp.gdpr = {
    getUserData: function(cb) { try { cb(_cd); } catch(e) {} },
    loadPrivacyManagerModal: function() {},
    reject: function() {}
  };
  _sp.ccpa = { getUserData: function(cb) { try { cb({ rejectedAll: true }); } catch(e) {} } };
  if (!_iotech) {
    var _q = window._sp_queue;
    window._sp_queue = { push: function(fn) { try { fn(); } catch(e) {} } };
    if (Array.isArray(_q)) _q.forEach(function(fn) { try { fn(); } catch(e) {} });
  }
})();

scripts.googleConsent:
if (window.location.hostname.indexOf('consent.google') >= 0 ||
    window.location.hostname.indexOf('accounts.google') >= 0) {
  function _clickGoogleReject() {
    var selectors = [
      'button[aria-label*="Reject"]','button[aria-label*="Hylkää"]',
      'button[aria-label*="Decline"]','button[aria-label*="Refuse"]',
      'form[action*="reject"] button','.tHlp8d','#W0wltc'
    ];
    for (var i = 0; i < selectors.length; i++) {
      var btn = document.querySelector(selectors[i]);
      if (btn) { btn.click(); return true; }
    }
    var buttons = document.querySelectorAll('button');
    var rejectWords = ['reject','hylkää','decline','refuse','kieltä'];
    for (var j = 0; j < buttons.length; j++) {
      var txt = (buttons[j].innerText || '').toLowerCase();
      if (rejectWords.some(function(w){ return txt.indexOf(w) >= 0; })) {
        buttons[j].click(); return true;
      }
    }
    return false;
  }
  setTimeout(function() {
    if (!_clickGoogleReject()) setTimeout(_clickGoogleReject, 1000);
  }, 500);
}
